     1	import { useState, type FormEvent } from 'react';
     2	import { useAuth } from '@rhino-dev/rhino-react';
     3	import { Icon } from '../components/Icons';
     4	import { useToast } from '../components/Toaster';
     5	
     6	const seededUsers = [
     7	  { email: 'alice@example.com', password: 'password', role: 'user' },
     8	  { email: 'bob@example.com',   password: 'password', role: 'user' },
     9	];
    10	
    11	export function LoginPage() {
    12	  const { login, setOrganization } = useAuth();
    13	  const toast = useToast();
    14	  const [email, setEmail] = useState('alice@example.com');
    15	  const [password, setPassword] = useState('password');
    16	  const [busy, setBusy] = useState(false);
    17	
    18	  async function handleSubmit(e: FormEvent) {
    19	    e.preventDefault();
    20	    setBusy(true);
    21	    const result = await login(email, password);
    22	    setBusy(false);
    23	    if (!result.success) {
    24	      toast(result.error ?? 'Login failed', 'error');
    25	      return;
    26	    }
    27	    toast(`Welcome, ${result.user?.name ?? email}`, 'ok');
    28	    // Stash the user info for the header chip and RBAC checks.
    29	    if (result.user?.name)  localStorage.setItem('rhino_user_name',  result.user.name);
    30	    if (result.user?.email) localStorage.setItem('rhino_user_email', result.user.email);
    31	    if (result.organization_slug) {
    32	      localStorage.setItem('rhino_organization_slug', result.organization_slug);
    33	      // The data hooks (useModelIndex etc.) read the org slug from the auth
    34	      // context, not localStorage — push it in or every request 400's with
    35	      // "Organization slug is required".
    36	      setOrganization(result.organization_slug);
    37	    }
    38	  }
    39	
    40	  return (
    41	    <div className="login-wrap">
    42	      <div className="login-card">
    43	        <div className="login-brand">
    44	          <div className="brand-mark">R</div>
    45	          <div className="brand-name">TaskFlow <span>/web</span></div>
    46	        </div>
    47	        <h1 className="login-title">Sign in to your workspace</h1>
    48	        <p className="login-sub">Multi-tenant project management — powered by Rhino.</p>
    49	
    50	        <form className="form" onSubmit={handleSubmit}>
    51	          <div className="field">
    52	            <label>Email</label>
    53	            <input className="input" type="email" autoFocus value={email} onChange={e => setEmail(e.target.value)} required />
    54	          </div>
    55	          <div className="field">
    56	            <label>Password</label>
    57	            <input className="input" type="password" value={password} onChange={e => setPassword(e.target.value)} required />
    58	          </div>
    59	          <button className="btn btn-primary" type="submit" disabled={busy} style={{ justifyContent: 'center' }}>
    60	            {busy ? <><span className="spinner" /> Signing in…</> : <><Icon.lock size={14} /> Sign in</>}
    61	          </button>
    62	        </form>
    63	
    64	        <div className="login-hint">
    65	          <b># Seeded accounts</b>
    66	          {seededUsers.map(u => (
    67	            <div key={u.email} style={{ marginTop: 4, cursor: 'pointer' }} onClick={() => { setEmail(u.email); setPassword(u.password); }}>
    68	              {u.email} · {u.password} <span className="faint">→ {u.role}</span>
    69	            </div>
    70	          ))}
    71	        </div>
    72	      </div>
    73	    </div>
    74	  );
    75	}
